#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        if ((K - 1) % 3 == 0 || (K - 1) % 3 == 1) {
            printf("yes\n");
        } else {
            printf("no\n");
        }
    }
    return 0;
}

